const raw = items[0].json;
const jsonStr = raw.replace(/^.*?\({/, '{').replace(/}\);?$/, '}');
const data = JSON.parse(jsonStr);
const rows = data.table.rows;
const header = data.table.cols.map(col => col.label);

const now = new Date();
const satuJamLalu = new Date(now.getTime() - 60 * 60 * 1000);
const today = now.toISOString().slice(0, 10);

function parseJam(jamStr) {
  const [jam, menit] = jamStr.split(":");
  const dt = new Date();
  dt.setHours(parseInt(jam));
  dt.setMinutes(parseInt(menit));
  dt.setSeconds(0);
  dt.setMilliseconds(0);
  return dt;
}

const hasil = rows.map(r => {
  const obj = {};
  header.forEach((key, idx) => obj[key] = r.c[idx]?.v);
  return obj;
}).filter(x => {
  if (x.Tanggal !== today) return false;
  const jamGempa = parseJam(x.Jam);
  return jamGempa >= satuJamLalu && jamGempa <= now;
});

if (hasil.length === 0) {
  return [{ json: { pesan: '📭 Tidak ada getaran dalam 1 jam terakhir.' } }];
}

const list = hasil.map(x => `- ${x.Jam} | ${x.Magnitude} SR | ${x.Wilayah}`).join("\n");
return [{ json: { pesan: `⏱️ *Getaran 1 Jam Terakhir*\n\n${list}` } }];
